import React, { useState } from 'react';

function App() {
  const [gpa, setGpa] = useState("");
  const [interests, setInterests] = useState("");

  const submitProfile = () => {
    if (!gpa || !interests) {
      alert("Please fill both GPA and Interests!");
      return;
    }
    alert(`🎓 Profile Saved!\nGPA: ${gpa}\nInterests: ${interests}\n\nAI Chat loads next!`);
  };

  return (
    <div style={{
      padding: "50px", 
      maxWidth: "500px", 
      margin: "auto", 
      textAlign: "center",
      border: "2px solid #007bff",
      borderRadius: "15px",
      background: "white",
      boxShadow: "0 10px 30px rgba(0,123,255,0.2)"
    }}>
      <h1 style={{ color: "#007bff", fontSize: "36px", marginBottom: "20px" }}>
        🎓 AI College Counselor
      </h1>
      
      <input 
        placeholder="Enter GPA (e.g. 3.5)" 
        value={gpa}
        onChange={(e) => setGpa(e.target.value)}
        style={{
          width: "100%", 
          padding: "15px", 
          fontSize: "18px",
          border: "2px solid #ddd",
          borderRadius: "10px",
          marginBottom: "15px",
          boxSizing: "border-box"
        }}
      />
      
      <input 
        placeholder="Interests (CS, AI, Mechanical)" 
        value={interests}
        onChange={(e) => setInterests(e.target.value)}
        style={{
          width: "100%", 
          padding: "15px", 
          fontSize: "18px",
          border: "2px solid #ddd",
          borderRadius: "10px",
          marginBottom: "20px",
          boxSizing: "border-box"
        }}
      />
      
      <button 
        onClick={submitProfile}
        style={{
          width: "100%",
          padding: "18px",
          background: "#28a745",
          color: "white",
          border: "none",
          borderRadius: "12px",
          fontSize: "20px",
          fontWeight: "bold",
          cursor: "pointer"
        }}
      >
        🚀 Start AI Counseling
      </button>
      
      <p style={{ marginTop: "25px", color: "#28a745", fontWeight: "bold" }}>
        Backend Status: localhost:5000 ✅
      </p>
    </div>
  );
}

export default App;
